import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"8. Roster","description":"","frontmatter":{"title":"8. Roster","eba":"Health Allied & Managers Admin 2021-2025","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/has-managers-admin/managers-admin/hours-of-work/8-roster.md","filePath":"ebas/has-managers-admin/managers-admin/hours-of-work/8-roster.md"}'),a={name:"ebas/has-managers-admin/managers-admin/hours-of-work/8-roster.md"};function n(i,e,l,d,h,p){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_8-roster" tabindex="-1">8. Roster <a class="header-anchor" href="#_8-roster" aria-label="Permalink to &quot;8. Roster&quot;">​</a></h1><p><strong>8.1</strong> This clause only applies to Employees who perform shiftwork within the meaning of Section 1 clause 45 (Shiftwork)</p><p><strong>8.2</strong> A roster of at least 14 days’ duration will be posted at least 14 days before it comes into operation at each work location in a place where it may be readily seen by such Employees and the Secretary or other accredited representative of the HWU.</p><p><strong>8.3</strong> Rosters will set out the Employees’ daily ordinary hours of work, start times, finish times and meal intervals.</p><p><strong>8.4</strong> Seven days’ notice will be given of a change in roster, except in emergency situations.</p><p><strong>8.5</strong> Change of roster</p><p><strong>(a)</strong> Where the Employer requires an Employee, without seven (7) days’ notice and outside the expected circumstances in subclause 8.2 above, to perform ordinary duty at other times than those previously rostered, the Employee will be paid in accordance with the hours worked plus a daily change of roster allowance pursuant to <a href="/eba/ebas/has-managers-admin/schedules/3c-allowances-managers-and-administrative-workers.html">Schedule 3C</a>.</p><p><strong>(b)</strong> Provided that a part-time Employee who agrees to work shift(s) in addition to those already rostered will not be entitled to the Change of Roster allowance for the additional shift(s) worked.</p><p><strong>8.6</strong> An Employee may apply in writing to the Employer to have their roster fixed by the provisions of subclause 8.7 below in lieu of clauses 8.2 to 8.5 above.</p><p><strong>8.7</strong> Rosters will be fixed by mutual agreement, subject to the provisions of the Agreement.</p><p><strong>8.8</strong> An Employee may repudiate a request made under clause 8.6 at any time, by giving written notice to the Employer. In such a case the roster of the Employee will be determined according to clauses 8.2 to 8.5 from the commencement of the next full roster period, being not less than five (5) clear days after such repudiation is received in writing by the Employer.</p><p><strong>8.9</strong> Rosters will be drawn up so as to provide at least eight (8) hours between successive periods of ordinary duty.</p>',12)])])}const u=t(a,[["render",n]]);export{c as __pageData,u as default};
